// Curated guitar song library organized by genre
// IDs start at 100 (1-99 reserved for manual entries in SONG_LIBRARY)
// Spotify API fetch script in scripts/spotify-fetch.mjs can enrich this data when API limits allow

function yt(title: string, artist: string): string {
  return `https://www.youtube.com/results?search_query=${encodeURIComponent(`how to play ${title} ${artist} guitar tutorial`)}`;
}

